div.div:
- Professional license number;
- Accounting service provider
Where the preparer is an accounting firm, state the professional license number, name and address of the accounting service provider. Where the preparer is an individual, state the professional license number.

div.script:
(function () {
    var b03dnI18n = {};
    try {
        var b03dnI18nEl = document.getElementById("b03dnReportI18n");
        if (b03dnI18nEl && b03dnI18nEl.textContent) {
            b03dnI18n = JSON.parse(b03dnI18nEl.textContent);
        }
    } catch (eI18n) { /* */ }
    function b03dnParseVnd(el) {
        var raw = el.getAttribute("data-vnd");
        if (raw === null || raw === "") { return 0; }
        var s = String(raw).replace(/\s/g, "").replace(/\u00a0/g, "");
        var x = parseFloat(s.replace(",", "."));
        return isNaN(x) ? 0 : x;
    }
    /** Số chữ số thập phân sau khi chia đơn vị — khớp res.currency.decimal_places + formatLang trên server */
    function b03dnCurrencyDecimalPlaces() {
        var root = document.getElementById("b03dn_report_root");
        if (!root) { return 0; }
        var n = parseInt(root.getAttribute("data-b03dn-currency-dp"), 10);
        if (isNaN(n) || n < 0) { return 0; }
        return n > 16 ? 16 : n;
    }
    function b03dnRoundScaled(val, dp) {
        if (dp <= 0) {
            return Math.round(val);
        }
        var p = Math.pow(10, dp);
        return Math.round(val * p) / p;
    }
    /**
     * Quy đổi từ số tiền gốc (VND) theo divisor; làm tròn giống tiền tệ (vd 123.456.789 đ → ngàn: 123.457).
     */
    function b03dnFormatFromVnd(vnd, divisor) {
        var dp = b03dnCurrencyDecimalPlaces();
        var d = divisor || 1;
        var v = Number(vnd);
        if (isNaN(v)) { v = 0; }
        var neg = v < 0;
        var u = Math.abs(v) / d;
        u = b03dnRoundScaled(u, dp);
        var s = u.toLocaleString("vi-VN", {
            minimumFractionDigits: dp,
            maximumFractionDigits: dp
        });
        return neg ? "(" + s + ")" : s;
    }
    function b03dnMoneyUnitCaptionText(val) {
        var v = String(val || "1");
        if (v === "1000") { return b03dnI18n.unit1000 || "Unit: thousands of VND"; }
        if (v === "1000000") { return b03dnI18n.unit1m || "Unit: millions of VND"; }
        return b03dnI18n.unitVnd || "Unit: VND";
    }
    function b03dnApplyMoneyUnit() {
        var root = document.getElementById("b03dn_report_root");
        var sel = document.getElementById("b03dnMoneyUnit");
        if (!root || !sel) { return; }
        var div = parseFloat(sel.value, 10) || 1;
        var nodes = root.querySelectorAll(".b03dn-amt[data-vnd]");
        for (var i = 0; i < nodes.length; i++) {
            nodes[i].textContent = b03dnFormatFromVnd(b03dnParseVnd(nodes[i]), div);
        }
        var cap = document.getElementById("b03dnMoneyUnitCaption");
        if (cap) {
            cap.textContent = b03dnMoneyUnitCaptionText(sel.value);
        }
    }
    /**
     * Sau AJAX thay bảng: OWL enrich không chạy lại — gắn drill-down gửi postMessage (cùng domain string như enrich).
     * Bỏ qua node đã bọc &lt;a&gt; từ lần load đầu.
     */
    function b03dnWireDrilldown(scope) {
        var root = scope || document;
        var nodes = root.querySelectorAll("[res-model][domain]");
        for (var i = 0; i < nodes.length; i++) {
            var el = nodes[i];
            if (el.dataset.b03dnDrillWired) { continue; }
            if (el.closest && el.closest('a[href]')) { continue; }
            el.dataset.b03dnDrillWired = "1";
            el.style.cursor = "pointer";
            el.addEventListener("click", function (ev) {
                ev.preventDefault();
                ev.stopPropagation();
                try {
                    window.parent.postMessage({
                        type: "b03dn_drilldown",
                        resModel: this.getAttribute("res-model"),
                        domain: this.getAttribute("domain"),
                    }, "*");
                } catch (e) { /* */ }
            });
        }
    }
    function b03dnWireTmLinks(scope) {
        var root = scope || document;
        var nodes = root.querySelectorAll(".b03dn-tm-link[data-b03dn-tm-code]");
        for (var i = 0; i < nodes.length; i++) {
            var el = nodes[i];
            if (el.dataset.b03dnTmWired) { continue; }
            el.dataset.b03dnTmWired = "1";
            el.addEventListener("click", function (ev) {
                ev.preventDefault();
                ev.stopPropagation();
                var aid = this.getAttribute("data-b03dn-tm-att");
                var code = this.getAttribute("data-b03dn-tm-code");
                var did = this.getAttribute("data-b03dn-tm-did");
                try {
                    var n = aid && String(aid).trim() ? parseInt(aid, 10) : 0;
                    if (!isNaN(n) && n > 0) {
                        window.parent.postMessage({
                            type: "b03dn_tm_document",
                            attachmentId: n,
                        }, "*");
                        return;
                    }
                    if (code && did) {
                        window.parent.postMessage({
                            type: "b03dn_tm_find_item",
                            dossierId: parseInt(did, 10) || 0,
                            fileCode: code,
                        }, "*");
                    }
                } catch (e2) { /* */ }
            });
        }
    }
    window.__b03dnGetFilterSnapshot = function () {
        var mu = document.getElementById("b03dnMoneyUnit");
        return {
            company_id: parseInt(document.getElementById("b03dnFilterCompany").value, 10) || 0,
            template_id: parseInt(document.getElementById("b03dnFilterTemplate").value, 10) || 0,
            date_from: document.getElementById("b03dnDf").value || "",
            date_to: document.getElementById("b03dnDt").value || "",
            date_from_cmp: document.getElementById("b03dnDfc").value || "",
            date_to_cmp: document.getElementById("b03dnDtc").value || "",
            signature_date: (function() { var s = document.getElementById("b03dnSigDate"); return s ? s.value : ""; }()),
            money_unit: mu ? parseInt(mu.value, 10) || 1 : 1
        };
    };
    var reloadTimer = null;
    function b03dnScheduleReload() {
        clearTimeout(reloadTimer);
        reloadTimer = setTimeout(function () {
            var el = document.getElementById("b03dnReportReload");
            if (!el) { return; }
            var opts = JSON.parse(el.textContent);
            opts.b03dn_ui_filters = window.__b03dnGetFilterSnapshot();
            var path = window.location.pathname.split("?")[0];
            var url = path + "?options=" + encodeURIComponent(JSON.stringify(opts));
            /* Keep ``context`` from the initial report URL (e.g. ``lang``); ``?options=`` alone drops it and QWeb reverts to en_US. */
            try {
                var qs = new URLSearchParams(window.location.search);
                var ctx = qs.get("context");
                if (ctx) {
                    url += "&context=" + encodeURIComponent(ctx);
                }
            } catch (eCtx) { /* */ }
            var host = document.getElementById("b03dnReportDataHost");
            if (!host) {
                window.location = url;
                return;
            }
            host.style.opacity = "0.45";
            host.style.pointerEvents = "none";
            fetch(url, { credentials: "same-origin" })
                .then(function (resp) { return resp.text(); })
                .then(function (html) {
                    var parser = new DOMParser();
                    var doc = parser.parseFromString(html, "text/html");
                    var newHost = doc.getElementById("b03dnReportDataHost");
                    var newReload = doc.getElementById("b03dnReportReload");
                    if (newHost) {
                        host.innerHTML = newHost.innerHTML;
                    }
                    if (newReload) {
                        el.textContent = newReload.textContent;
                    }
                    b03dnWireDrilldown(host);
                    b03dnWireTmLinks(host);
                    b03dnApplyMoneyUnit();
                    b03dnWireSignaturePicker();
                    host.style.opacity = "";
                    host.style.pointerEvents = "";
                })
                .catch(function () {
                    window.location = url;
                });
        }, 450);
    }
    var moneyUnitSel = document.getElementById("b03dnMoneyUnit");
    if (moneyUnitSel) {
        var initialMu = moneyUnitSel.getAttribute("data-initial-money-unit");
        var muSt = null;
        try { muSt = sessionStorage.getItem("b03dnMoneyUnit"); } catch (eMu) { /* */ }
        if (initialMu === "1" || initialMu === "1000" || initialMu === "1000000") {
            moneyUnitSel.value = initialMu;
        } else if (muSt === "1" || muSt === "1000" || muSt === "1000000") {
            moneyUnitSel.value = muSt;
        }
        moneyUnitSel.addEventListener("change", function () {
            try {
                sessionStorage.setItem("b03dnMoneyUnit", moneyUnitSel.value);
            } catch (eSt) { /* */ }
            b03dnApplyMoneyUnit();
        });
        b03dnApplyMoneyUnit();
    }
    ["b03dnFilterCompany", "b03dnFilterTemplate", "b03dnDf", "b03dnDt", "b03dnDfc", "b03dnDtc"].forEach(function (id) {
        var n = document.getElementById(id);
        if (n) { n.addEventListener("change", b03dnScheduleReload); }
    });
    var b03dnToolbar = document.getElementById("b03dnToolbar");
    var b03dnToolbarBody = document.getElementById("b03dnToolbarBody");
    var b03dnFilterToggle = document.getElementById("b03dnFilterToggle");
    if (b03dnToolbar && b03dnToolbarBody && b03dnFilterToggle) {
        function b03dnApplyToolbarCollapsed(collapsed) {
            b03dnToolbar.classList.toggle("b03dn-toolbar-collapsed", collapsed);
            b03dnToolbarBody.classList.toggle("b03dn-toolbar-body--hidden", collapsed);
            b03dnFilterToggle.setAttribute("aria-expanded", collapsed ? "false" : "true");
            try {
                sessionStorage.setItem("b03dnToolbarCollapsed", collapsed ? "1" : "0");
            } catch (e1) { /* private mode */ }
        }
        try {
            if (sessionStorage.getItem("b03dnToolbarCollapsed") === "1") {
                b03dnApplyToolbarCollapsed(true);
            }
        } catch (e2) { /* */ }
        b03dnFilterToggle.addEventListener("click", function (ev) {
            ev.stopPropagation();
            b03dnApplyToolbarCollapsed(
                !b03dnToolbar.classList.contains("b03dn-toolbar-collapsed"),
            );
        });
    }

    function b03dnWireSignaturePicker() {
        var sigInline = document.getElementById("b03dnSignatureDateInline");
        var sigDisplay = document.getElementById("b03dnLapDateDisplay");
        var sigHidden = document.getElementById("b03dnSigDate");
        if (!sigInline || !sigDisplay) return;
        if (sigInline.dataset.b03dnSigWired) return;
        sigInline.dataset.b03dnSigWired = "1";
        sigInline.addEventListener("change", function () {
            if (!this.value) return;
            var d = new Date(this.value + 'T00:00:00');
            var dd = String(d.getDate()).padStart(2, '0');
            var mm = String(d.getMonth() + 1).padStart(2, '0');
            var yy = d.getFullYear();
            var datedTpl = b03dnI18n.datedFormat || "dated %s/%s/%s";
            var datedFmt = datedTpl.replace("%s", dd).replace("%s", mm).replace("%s", String(yy));
            sigDisplay.textContent = datedFmt;
            if (sigHidden) { sigHidden.value = this.value; }
            b03dnScheduleReload();
        });
    }
    b03dnWireSignaturePicker();
    b03dnWireDrilldown(document);
    b03dnWireTmLinks(document);

})();
